#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
QUICK = Path("lib/quick_modes.dart")
PUBSPEC = Path("pubspec.yaml")
TARGET = Path("lib/advanced_modes.dart")

ADVANCED_MODES_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, QUICK, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
quick = QUICK.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

if "part 'advanced_modes.dart';" in main or TARGET.exists():
    raise SystemExit(
        "Gelişmiş oyun modları zaten kurulmuş görünüyor."
    )

required_main = [
    "part 'quick_modes.dart';",
    "Bilgi Rotası • Sürüm 1.23",
]

required_quick = [
    "class QuickModesHubScreen",
    "title: 'Kategori Düellosu'",
    "CategoryDuelSetupScreen(",
    "'Üç farklı mücadele'",
]

for marker in required_main:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

for marker in required_quick:
    if marker not in quick:
        raise SystemExit(
            f"Beklenen quick_modes.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 23):
    raise SystemExit(
        "Bu paket 1.23.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.24.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_advanced_modes_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(QUICK, backup_dir / "quick_modes.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    TARGET.write_text(
        base64.b64decode(
            ADVANCED_MODES_B64
        ).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "part 'quick_modes.dart';",
        "part 'quick_modes.dart';\n"
        "part 'advanced_modes.dart';",
        1,
    )

    main, display_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.23",
        "Bilgi Rotası • Sürüm 1.24",
        main,
        count=1,
    )

    if display_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    quick = quick.replace(
        "'Yeni Modlar • Hayatta Kal, 60 Saniye, Düello'",
        "'7 Oyun Modu • Hız, Aile, Takım, Turnuva'",
        1,
    )

    quick = quick.replace(
        "'❤️⚡⚔️'",
        "'❤️⚡⚔️👨‍👩‍👧‍👦🤝🏆🎭'",
        1,
    )

    quick = quick.replace(
        "'Üç farklı mücadele'",
        "'Yedi farklı mücadele'",
        1,
    )

    quick = quick.replace(
        "'Canlarını koru, zamana karşı yarış ve rakibine meydan oku.'",
        "'Hız, aile, takım, turnuva ve sürpriz kurallarla her oyunda başka bir rota.'",
        1,
    )

    insert_marker = """                  const SizedBox(height: 16),
                  Container(
                    padding: const EdgeInsets.all(15),
                    decoration: BoxDecoration(
"""

    if insert_marker not in quick:
        raise RuntimeError(
            "Yeni mod kartlarının ekleneceği bölüm bulunamadı."
        )

    advanced_cards = """                  const SizedBox(height: 12),
                  _modeCard(
                    emoji: '👨‍👩‍👧‍👦',
                    title: 'Aile Modu',
                    description:
                        'Çocuk ve yetişkinler kendi zorluk seviyelerinde aynı turda yarışır.',
                    record: '2–6 oyuncu • Kişiye göre zorluk',
                    colors: const [
                      Color(0xFF0F766E),
                      Color(0xFF2563EB),
                    ],
                    onTap: () => _open(
                      FamilyModeSetupScreen(
                        questionBank: widget.questionBank,
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  _modeCard(
                    emoji: '🤝',
                    title: 'Takım Modu',
                    description:
                        'İki takım altı kategorinin tamamında ortak bilgiyle mücadele eder.',
                    record: '2 takım • Paylaşılan jokerler',
                    colors: const [
                      Color(0xFF6D28D9),
                      Color(0xFF0F766E),
                    ],
                    onTap: () => _open(
                      TeamModeSetupScreen(
                        questionBank: widget.questionBank,
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  _modeCard(
                    emoji: '🏆',
                    title: 'Turnuva Modu',
                    description:
                        '4 veya 8 oyunculu eleme ağacında yarı final ve finale yüksel.',
                    record: 'Tek kaybeden elenir',
                    colors: const [
                      Color(0xFF92400E),
                      Color(0xFF7C3AED),
                    ],
                    onTap: () => _open(
                      TournamentSetupScreen(
                        questionBank: widget.questionBank,
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  _modeCard(
                    emoji: '🎭',
                    title: 'Karışık Çılgınlık',
                    description:
                        'Her soruda çifte XP, karışık şıklar veya joker hediyesi gibi sürprizler.',
                    record: '15 soru • 7 rastgele kural',
                    colors: const [
                      Color(0xFF7C2D12),
                      Color(0xFF6D28D9),
                    ],
                    onTap: () => _open(
                      MixedMadnessIntroScreen(
                        questionBank: widget.questionBank,
                      ),
                    ),
                  ),
                  const SizedBox(height: 16),
                  Container(
                    padding: const EdgeInsets.all(15),
                    decoration: BoxDecoration(
"""

    quick = quick.replace(
        insert_marker,
        advanced_cards,
        1,
    )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    QUICK.write_text(quick, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "part 'advanced_modes.dart';",
            "Bilgi Rotası • Sürüm 1.24",
        ],
        QUICK: [
            "FamilyModeSetupScreen(",
            "TeamModeSetupScreen(",
            "TournamentSetupScreen(",
            "MixedMadnessIntroScreen(",
            "Yedi farklı mücadele",
        ],
        TARGET: [
            "class FamilyModeGameScreen",
            "class TeamModeGameScreen",
            "class TournamentGameScreen",
            "class MixedMadnessGameScreen",
            "enum MadnessRule",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/quick_modes.dart",
            "lib/advanced_modes.dart",
        ])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])

    run([
        "git",
        "add",
        "lib/main.dart",
        "lib/quick_modes.dart",
        "lib/advanced_modes.dart",
        "pubspec.yaml",
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Aile Takim Turnuva ve Karisik Cilginlik modlari",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "quick_modes.dart",
            QUICK,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        if TARGET.exists():
            TARGET.unlink()

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                "lib/main.dart",
                "lib/quick_modes.dart",
                "lib/advanced_modes.dart",
                "pubspec.yaml",
            ],
            check=False,
        )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Dosyalar önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Aile Modu eklendi.")
print("✅ Takım Modu eklendi.")
print("✅ 4 ve 8 oyunculu Turnuva Modu eklendi.")
print("✅ Karışık Çılgınlık ve 7 rastgele kural eklendi.")
print("✅ Yeni modlar mevcut XP, seri, joker ve istatistik sistemine bağlandı.")
print("✅ Yeni Modlar ekranı 7 moda genişletildi.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
